import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSSecureCode {

    public void handleUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Properly encode user input to prevent XSS attacks
        String safeUserInput = encodeForHtml(userInput);

        String output = "<p>User input: " + safeUserInput + "</p>";

        // Output the sanitized user input
        response.getWriter().write(output);
    }

    private String encodeForHtml(String input) {
        if (input == null) {
            return "";
        }

        return input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;")
                .replace("/", "&#x2F;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
